SELECT
  SUM( CASE  WHEN (
  amd_odbc_ehr_itemdiagnosis__dlm.DiagnosisCode__c = &#39;I83.10&#39;
  or amd_odbc_ehr_itemdiagnosis__dlm.DiagnosisCode__c = &#39;I83.11&#39;
  or amd_odbc_ehr_itemdiagnosis__dlm.DiagnosisCode__c = &#39;I83.12&#39;
  or amd_odbc_ehr_itemdiagnosis__dlm.DiagnosisCode__c = &#39;I83.811&#39;
  or amd_odbc_ehr_itemdiagnosis__dlm.DiagnosisCode__c = &#39;I83.812&#39;
  or amd_odbc_ehr_itemdiagnosis__dlm.DiagnosisCode__c = &#39;I83.813&#39;
  or amd_odbc_ehr_itemdiagnosis__dlm.DiagnosisCode__c = &#39;I83.819&#39;
  or amd_odbc_ehr_itemdiagnosis__dlm.DiagnosisCode__c = &#39;I83.891&#39;
  or amd_odbc_ehr_itemdiagnosis__dlm.DiagnosisCode__c = &#39;I83.892&#39;
  or amd_odbc_ehr_itemdiagnosis__dlm.DiagnosisCode__c = &#39;I83.893&#39;
  or amd_odbc_ehr_itemdiagnosis__dlm.DiagnosisCode__c = &#39;I83.899&#39;
) THEN 1 ELSE 0 END) AS superficialvenousdisease__c,
  UnifiedIndividual__dlm.ssot__Id__c AS unified_individual__c,
  ssot__Individual__dlm.ssot__Id__c AS individual__c,
  ssot__Individual__dlm.KQ_Id__c AS key_qualifier_individual__c
FROM UnifiedIndividual__dlm
  LEFT OUTER JOIN IndividualIdentityLink__dlm
    ON (UnifiedIndividual__dlm.ssot__Id__c = IndividualIdentityLink__dlm.UnifiedRecordId__c)
  LEFT OUTER JOIN ssot__Individual__dlm
    ON (IndividualIdentityLink__dlm.SourceRecordId__c = ssot__Individual__dlm.ssot__Id__c AND IndividualIdentityLink__dlm.KQ_SourceRecordId__c = ssot__Individual__dlm.KQ_Id__c)
  JOIN amd_odbc_ehr_itemdiagnosis__dlm
    ON (ssot__Individual__dlm.ssot__Id__c = amd_odbc_ehr_itemdiagnosis__dlm.PatientID__c AND ssot__Individual__dlm.KQ_Id__c = amd_odbc_ehr_itemdiagnosis__dlm.KQ_PatientID__c)
GROUP BY
  unified_individual__c,
  individual__c,
  key_qualifier_individual__c
